// optional import of sdk modules
import { execution } from '@dynatrace-sdk/automation-utils';
import { workflowsClient } from '@dynatrace-sdk/client-automation';

export default async function ({ payloadJson }) {
  const ex = await execution();
  const body = payloadJson && payloadJson.trim() ? JSON.parse(payloadJson) : {};
  const result = await workflowsClient.createWorkflow({ body });

  return {
    operation: 'dynatrace create workflow',
    triggeredBy: ex.trigger,
    result
  };
}
